for (const node of topologicalSort(inheritanceGraph).reverse()) {
  const existingMemberIncompatibility =
    node.data.info.memberIncompatibility !== null
      ? {reason: node.data.info.memberIncompatibility, context: null}
      : null;

  for (const parent of node.outgoing) {
    // If parent is incompatible and not migrated, then this input
    // cannot be migrated either. Try propagating parent incompatibility then.
    if (isNodeIncompatible(parent.data)) {
      node.data.info.memberIncompatibility = pickFieldIncompatibility(
        {reason: FieldIncompatibilityReason.ParentIsIncompatible, context: null},
        existingMemberIncompatibility,
      ).reason;
      break;
    }
  }
}

if (interceptionPoint === InterceptionPoint.REQUEST) {
  if (this.requestInterceptorConfig) {
    throw new ValidationError(
      lit`RequestInterceptorAlreadyExists`,
      'Gateway already has a REQUEST interceptor configured. A gateway can have at most one REQUEST interceptor.',
      this,
    );
  }
  this.requestInterceptorConfig = interceptor.bind(this, this);
} else if (interceptionPoint === InterceptionPoint.RESPONSE) {
  if (this.responseInterceptorConfig) {
    throw new ValidationError(
      lit`ResponseInterceptorAlreadyExists`,
      'Gateway already has a RESPONSE interceptor configured. A gateway can have at most one RESPONSE interceptor.',
      this,
    );
  }
  this.responseInterceptorConfig = interceptor.bind(this, this);
}

try {
  switch (event.RequestType) {
    case 'Create':
      console.info('Tagging SSM Parameter imports');
      await addTags(ssm, importNames, keyName);
      break;
    case 'Update':
      const oldProps: ExportReaderCRProps = event.OldResourceProperties.ReaderProps;
      const oldExports: CrossRegionExports = oldProps.imports as CrossRegionExports;
      const newExports = except(importNames, Object.keys(oldExports));
      const paramsToRelease = except(Object.keys(oldExports), importNames);
      console.info('Releasing unused SSM Parameter imports');
      if (Object.keys(paramsToRelease).length > 0) {
        await removeTags(ssm, paramsToRelease, keyName);
      }
      console.info('Tagging new SSM Parameter imports');
      await addTags(ssm, newExports, keyName);
      break;
    case 'Delete':
      console.info('Releasing all SSM Parameter exports by removing tags');
      await removeTags(ssm, importNames, keyName);
      return;
  }
} catch (e) {
  console.error('Error importing cross region stack exports: ', e);
  throw e;
}

if (getVersionMessage) {
  let touchedFile: string | undefined;
  // Note, git gets angry if you try and have two git actions running at once
  // So we need to be careful that these iterations are properly sequential
  while ((touchedFile = touchedFiles.shift())) {
    await git.add(path.relative(cwd, touchedFile), cwd);
  }

  const commit = await git.commit(
    await getVersionMessage(releasePlan, commitOpts),
    cwd
  );

  if (!commit) {
    error("Changesets ran into trouble committing your files");
  } else {
    log(
      "All files have been updated and committed. You're ready to publish!"
    );
  }
} else {
  log("All files have been updated. Review them and commit at your leisure");
}

for (const adj of adjustments) {
  if (!isDefined(adj.amount)) {
    continue
  }

  const adjustmentSubtotal =
    isDefined(taxRate) && adj.is_tax_inclusive
      ? MathBN.div(adj.amount, MathBN.add(1, taxRate))
      : adj.amount

  const adjustmentTaxTotal = isDefined(taxRate)
    ? MathBN.mult(adjustmentSubtotal, taxRate)
    : 0
  const adjustmentTotal = MathBN.add(adjustmentSubtotal, adjustmentTaxTotal)

  adjustmentsSubtotal = MathBN.add(adjustmentsSubtotal, adjustmentSubtotal)
  adjustmentsTaxTotal = MathBN.add(adjustmentsTaxTotal, adjustmentTaxTotal)
  adjustmentsTotal = MathBN.add(adjustmentsTotal, adjustmentTotal)

  adj["subtotal"] = new BigNumber(adjustmentsSubtotal)
  adj["total"] = new BigNumber(adjustmentsTotal)
}

switch (requestDestination) {
  case 'audio': return 'media';
  case 'audioworklet': return 'script';
  case 'document': return 'document';
  case 'font': return 'font';
  case 'frame': return 'document';
  case 'iframe': return 'document';
  case 'image': return 'image';
  case 'object': return 'other';
  case 'paintworklet': return 'script';
  case 'script': return 'script';
  case 'serviceworker': return 'script';
  case 'sharedworker': return 'script';
  case 'style': return 'stylesheet';
  case 'track': return 'texttrack';
  case 'video': return 'media';
  case 'worker': return 'script';
  case '':
    switch (requestInitiatorType) {
      case 'fetch': return 'fetch';
      case 'font': return 'font';
      case 'xmlhttprequest': return 'xhr';
      case null: return eventInitiatorType === 'script' ? 'xhr' : 'document';
      default: return 'other';
    }
  default: return 'other';
}

if (node.d.imports.length > 0) {
    const importStatementPos = convertOffsetToPosition(node.start, parseFileResults.tokenizerOutput.lines);
    const firstSymbolPos = convertOffsetToPosition(node.d.imports[0].start, parseFileResults.tokenizerOutput.lines);
    const secondSymbolPos =
        node.d.imports.length > 1
            ? convertOffsetToPosition(node.d.imports[1].start, parseFileResults.tokenizerOutput.lines)
            : undefined;

    if (
        firstSymbolPos.line > importStatementPos.line &&
        (secondSymbolPos === undefined || secondSymbolPos.line > firstSymbolPos.line)
    ) {
        const firstSymbolLineRange = parseFileResults.tokenizerOutput.lines.getItemAt(firstSymbolPos.line);

        // Use the same combination of spaces or tabs to match
        // existing formatting.
        indentText = parseFileResults.text.substr(firstSymbolLineRange.start, firstSymbolPos.character);

        // Is the indent text composed of whitespace only?
        if (indentTextRegEx.test(indentText)) {
            useOnePerLineFormatting = true;
        }
    }
}

if (typesAreConsistent && destType.shared.typeParams.length > 0) {
    // Create a specialized version of the protocol defined by the dest and
    // make sure the resulting type args can be assigned.
    const genericProtocolType = ClassType.specialize(destType, undefined);
    const specializedProtocolType = evaluator.solveAndApplyConstraints(
        genericProtocolType,
        protocolConstraints
    ) as ClassType;

    if (destType.priv.typeArgs) {
        if (
            !evaluator.assignTypeArgs(destType, specializedProtocolType, diag, constraints, flags, recursionCount)
        ) {
            typesAreConsistent = false;
        }
    } else if (constraints) {
        for (const typeParam of destType.shared.typeParams) {
            const typeArgEntry = protocolConstraints.getMainConstraintSet().getTypeVar(typeParam);

            if (typeArgEntry) {
                constraints.copyBounds(typeArgEntry);
            }
        }
    }
}

if (apiItem instanceof ApiClass) {
  if (apiItem.extendsType) {
    const extendsParagraph: DocParagraph = new DocParagraph({ configuration }, [
      new DocEmphasisSpan({ configuration, bold: true }, [
        new DocPlainText({ configuration, text: 'Extends: ' })
      ])
    ]);
    this._appendExcerptWithHyperlinks(extendsParagraph, apiItem.extendsType.excerpt);
    output.appendNode(extendsParagraph);
  }
  if (apiItem.implementsTypes.length > 0) {
    const implementsParagraph: DocParagraph = new DocParagraph({ configuration }, [
      new DocEmphasisSpan({ configuration, bold: true }, [
        new DocPlainText({ configuration, text: 'Implements: ' })
      ])
    ]);
    let needsComma: boolean = false;
    for (const implementsType of apiItem.implementsTypes) {
      if (needsComma) {
        implementsParagraph.appendNode(new DocPlainText({ configuration, text: ', ' }));
      }
      this._appendExcerptWithHyperlinks(implementsParagraph, implementsType.excerpt);
      needsComma = true;
    }
    output.appendNode(implementsParagraph);
  }
}

if (!packageMetadata) {
  const packageJson: INodePackageJson = this._packageJsonLookup.loadNodePackageJson(packageJsonFilePath);

  const packageJsonFolder: string = path.dirname(packageJsonFilePath);

  let aedocSupported: boolean = false;

  const tsdocMetadataPath: string = PackageMetadataManager._resolveTsdocMetadataPathFromPackageJson(
    packageJsonFolder,
    packageJson
  );

  if (FileSystem.exists(tsdocMetadataPath)) {
    this._messageRouter.logVerbose(
      ConsoleMessageId.FoundTSDocMetadata,
      'Found metadata in ' + tsdocMetadataPath
    );
    // If the file exists at all, assume it was written by API Extractor
    aedocSupported = true;
  }

  packageMetadata = new PackageMetadata(packageJsonFilePath, packageJson, aedocSupported);
  this._packageMetadataByPackageJsonPath.set(packageJsonFilePath, packageMetadata);
}

if (edits.length > 0) {
	const last = edits[edits.length - 1];
	const overlaps = editsOverlap(incoming, last, config.editMergeLineDistance);

	if (overlaps) {
		// build the file state _just before_ the incoming edit
		const prevLines = applyEditsToLines(originalContent.split('\n'), edits.slice(0, -1));

		// compute the true minimal span
		const span = findChangeSpan(prevLines, currentFileLines);
		if (span) {
			// re-build a single merged hunk
			incoming = buildIncomingEdit(incoming.file, prevLines, currentFileLines, span, config);
			edits = [...edits.slice(0, -1), incoming];
		}
		// else a no-op or perfect revert, just drop the incoming
	} else {
		edits.push(incoming);
	}
} else {
	edits.push(incoming);
}

if (newLocaleText.length > 0) {
  if (needsWrapper[componentName]) {
    // From : https://www.codeshiftcommunity.com/docs/react/#wrapping-components

    // Create a new JSXElement called "LocalizationProvider" and use the original component as children
    const wrappedComponent = j.jsxElement(
      j.jsxOpeningElement(j.jsxIdentifier('LocalizationProvider'), [
        // Add the new localeText prop
        j.jsxAttribute(
          j.jsxIdentifier('localeText'),
          j.jsxExpressionContainer(j.objectExpression(newLocaleText)),
        ),
      ]),
      j.jsxClosingElement(j.jsxIdentifier('LocalizationProvider')),
      [path.value], // Pass in the original component as children
    );

    j(path).replaceWith(wrappedComponent);
  } else {
    attributes.push(
      j.jsxAttribute(
        j.jsxIdentifier('localeText'),
        j.jsxExpressionContainer(j.objectExpression(newLocaleText)),
      ),
    );
  }
}

if (!didMoveRef.current && isDifferentFromSource) {
  // A custom day slot could strip `data-position`; without it the preview
  // would compute against the wrong endpoint, so abort the drag rather
  // than rendering something misleading.
  if (!sourcePositionRef.current) {
    if (process.env.NODE_ENV !== 'production') {
      console.warn(
        'MUI X: A drag was initiated on a day cell missing `data-position`. ' +
          'Drag editing requires the cell to advertise which range endpoint it represents.',
      );
    }
    return;
  }

  // First real move: activate drag UI and tell the parent which endpoint
  // is being dragged so the preview computes against the correct side.
  didMoveRef.current = true;
  onDatePositionChange(sourcePositionRef.current);
  setIsDragging(true);
}

try {
  const contextId = this.getContextId(req, isTreeDurable);
  const contextInstance = await this.injector.loadPerContext(
    instance,
    moduleRef,
    collection,
    contextId,
  );
  const proxy = await this.createProxy<TRequest, TResponse>(
    contextInstance,
    contextId,
  );
  return proxy(req, res, next);
} catch (err) {
  let exceptionsHandler = this.exceptionFiltersCache.get(instance.use);
  if (!exceptionsHandler) {
    exceptionsHandler = this.routerExceptionFilter.create(
      instance,
      instance.use,
      undefined,
    );
    this.exceptionFiltersCache.set(instance.use, exceptionsHandler);
  }
  const host = new ExecutionContextHost([req, res, next]);
  exceptionsHandler.next(err, host);
}

if (name) {
  // Considering native commands before native nestjs injected functions.
  const nativeCommandOrFunction =
    this.commands[name] || this.context[name];
  // NOTE: If the command was retrieve from the context, it will have a `help`
  // getter property that outputs the helper message and returns undefined.
  // But if the command was retrieve from the `commands` object, it will
  // have a `help` property that returns the helper message.
  const helpMessage = nativeCommandOrFunction?.help;
  if (helpMessage) {
    this.output.write(`${helpMessage}\n`);
  }
} else {
  listAllCommands(this);
  this.output.write('\n\n');
  this.context.help();
  this.output.write(
    '\nPress Ctrl+C to abort current expression, Ctrl+D to exit the REPL\n',
  );
}

if (targetConfiguration.configurations) {
  for (const configurationObject of Object.values(
    targetConfiguration.configurations
  )) {
    if (configurationObject.command) {
      collectJestConfigFromCommand(
        configurationObject.command,
        configurationObject.cwd ?? projectRoot,
        jestConfigurations
      );
    } else if (configurationObject.commands) {
      for (const command of configurationObject.commands) {
        const commandScript =
          typeof command === 'string' ? command : command.command;
        collectJestConfigFromCommand(
          commandScript,
          configurationObject.cwd ?? projectRoot,
          jestConfigurations
        );
      }
    }
  }
}

if (args.cron) {
  new Cron(
    args.cron,
    async () => {
      // If the bin script initializes payload (getPayload), this will only happen once, as getPayload
      // caches the payload instance on the module scope => no need to manually cache and manage getPayload initialization
      // outside the Cron here.
      await runBinScript({ args, script })
    },
    {
      // Do not run consecutive crons if previous crons still ongoing
      protect: true,
    },
  )

  process.stdin.resume() // Keep the process alive

  return
} else {
  const { payload } = await runBinScript({ args, script })
  if (payload) {
    await payload.destroy() // close database connections after running jobs so process can exit cleanly
  }
  process.exit(0)
}

if (sanitizedPluginConfig.addresses) {
  addressFields = sanitizedPluginConfig.addresses.addressFields

  const supportedCountries = sanitizedPluginConfig.addresses.supportedCountries

  const defaultAddressesCollection = createAddressesCollection({
    access: accessConfig,
    addressFields,
    customersSlug: collectionSlugMap.customers,
    supportedCountries,
  })

  const addressesCollection =
    sanitizedPluginConfig.addresses &&
    typeof sanitizedPluginConfig.addresses === 'object' &&
    'addressesCollectionOverride' in sanitizedPluginConfig.addresses &&
    sanitizedPluginConfig.addresses.addressesCollectionOverride
      ? await sanitizedPluginConfig.addresses.addressesCollectionOverride({
          defaultCollection: defaultAddressesCollection,
        })
      : defaultAddressesCollection

  incomingConfig.collections.push(addressesCollection)
}

for (const [pkgName, vulnerabilities] of vulnerabilitiesByPackage) {
  const updatedVersions = updatedPackages.get(pkgName)
  if (!updatedVersions) {
    fixed.push(...vulnerabilities.map(v => v.id))
    continue
  }
  for (const vulnerability of vulnerabilities) {
    let wasFixed = true
    for (const updatedVersion of updatedVersions) {
      let { semverRange } = vulnerability
      if (!semverRange) {
        semverRange = new semver.Range(vulnerability.vulnerability.versionRange)
        vulnerability.semverRange = semverRange
      }
      if (semver.satisfies(updatedVersion, semverRange)) {
        wasFixed = false
        break
      }
    }
    if (wasFixed) {
      fixed.push(vulnerability.id)
    } else {
      remaining.push(vulnerability.id)
    }
  }
}

if (this.#executorKind.remote) {
  return new RemoteExecutor({
    clientVersion: this.config.clientVersion,
    accelerateUrl: this.#executorKind.accelerateUrl,
    logEmitter: this.logEmitter,
    logLevel: this.logLevel,
    logQueries: this.logQueries,
    tracingHelper: this.tracingHelper,
    sqlCommenters: this.config.sqlCommenters,
  })
} else {
  return await LocalExecutor.connect({
    driverAdapterFactory: this.#executorKind.driverAdapterFactory,
    tracingHelper: this.tracingHelper,
    transactionOptions: {
      ...this.config.transactionOptions,
      isolationLevel: this.#convertIsolationLevel(this.config.transactionOptions.isolationLevel),
    },
    onQuery: this.#emitQueryEvent,
    provider: this.config.activeProvider as ActiveConnectorType | undefined,
    sqlCommenters: this.config.sqlCommenters,
  })
}

if ('serializeQueryArgs' in queryArgsApi.endpointDefinition) {
  const endpointSQA =
    queryArgsApi.endpointDefinition.serializeQueryArgs!
  finalSerializeQueryArgs = (queryArgsApi) => {
    const initialResult = endpointSQA(queryArgsApi)
    if (typeof initialResult === 'string') {
      // If the user function returned a string, use it as-is
      return initialResult
    } else {
      // Assume they returned an object (such as a subset of the original
      // query args) or a primitive, and serialize it ourselves
      return defaultSerializeQueryArgs({
        ...queryArgsApi,
        queryArgs: initialResult,
      })
    }
  }
} else if (options.serializeQueryArgs) {
  finalSerializeQueryArgs = options.serializeQueryArgs
}

for (let [currentExportName, currentDependencies] of exportDependencies) {
  if (currentExportName === exportName) {
    continue;
  }

  // As soon as we find any top level non-import statements in common with
  // another export, we know this export cannot be placed in its own
  // chunk. The reason import statements aren't factored into this check
  // is because we perform more fine-grained optimizations on them,
  // filtering out all unused imports within each chunk, meaning that it's
  // okay for multiple exports to share an import statement. We perform a
  // deeper check on imported identifiers in the step after this.
  if (
    setsIntersect(
      currentDependencies.topLevelNonModuleStatements,
      dependencies.topLevelNonModuleStatements,
    )
  ) {
    return false;
  }
}

if (hashPlaceholder) {
	// To create a reproducible content-only hash, all placeholders are
	// replaced with the same value before hashing
	const { containedPlaceholders, transformedCode } =
		replacePlaceholdersWithDefaultAndGetContainedPlaceholders(code, placeholders);
	let contentToHash = transformedCode;
	const hashAugmentation = pluginDriver.hookReduceValueSync(
		'augmentChunkHash',
		'',
		[chunk.getRenderedChunkInfo()],
		(augmentation, pluginHash) => {
			if (pluginHash) {
				augmentation += pluginHash;
			}
			return augmentation;
		}
	);
	if (hashAugmentation) {
		contentToHash += hashAugmentation;
	}
	renderedChunksByPlaceholder.set(hashPlaceholder, transformedChunk);
	hashDependenciesByPlaceholder.set(hashPlaceholder, {
		containedPlaceholders,
		contentHash: getHash(contentToHash)
	});
} else {
	nonHashedChunksWithPlaceholders.push(transformedChunk);
}

try {
  if (!isCI()) {
    const { hasEslint, isStorybookPluginInstalled, isFlatConfig, eslintConfigFile } =
      // TODO: Investigate why packageManager type does not match on CI
      await extractEslintInfo(packageManager as any);

    if (hasEslint && !isStorybookPluginInstalled) {
      eslintPluginPackage = 'eslint-plugin-storybook';
      packagesToInstall.push(eslintPluginPackage);
      taskLog.message(`- Configuring ESLint plugin`);
      await configureEslintPlugin({
        eslintConfigFile,
        // TODO: Investigate why packageManager type does not match on CI
        packageManager: packageManager as any,
        isFlatConfig,
      });
    }
  }
} catch (err) {
  // any failure regarding configuring the eslint plugin should not fail the whole generator
}

try {
  const { queries, combine } = resolveQueriesOptions(
    this.options,
    queryClient,
  )
  this.queries = queries
  this.combine = combine
  const observer = new QueriesObserver(queryClient, this.queries, {
    combine: this.combine,
  } as QueriesObserverOptions<TCombinedResult>)
  this.queryClient = queryClient
  this.observer = observer
  this.assignObserverResult(observer.getCurrentResult(), true)
  this.explicitInitializationError = undefined
  this.placeholderInitialized = true
  return true
} catch (error) {
  // Retry after construction completes so late host fields used by
  // static queries/combine callbacks can finish initializing first.
  this.explicitInitializationError = error
  this.queryClient = undefined
  this.observer = undefined
  return false
}

if (doScriptMode) {
  // Use node's own resolution behavior to ensure we follow symlinks.
  // scriptPath may omit file extension or point to a directory with or without package.json.
  // This happens before we are registered, so we tell node's resolver to consider ts, tsx, and jsx files.
  // In extremely rare cases, is is technically possible to resolve the wrong directory,
  // because we do not yet know preferTsExts, jsx, nor allowJs.
  // See also, justification why this will not happen in real-world situations:
  // https://github.com/TypeStrong/ts-node/pull/1009#issuecomment-613017081
  const exts = ['.js', '.jsx', '.ts', '.tsx'];
  const extsTemporarilyInstalled: string[] = [];
  for (const ext of exts) {
    if (!hasOwnProperty(require.extensions, ext)) {
      extsTemporarilyInstalled.push(ext);
      require.extensions[ext] = function () {};
    }
  }
  try {
    return dirname(requireResolveNonCached(scriptPath!));
  } finally {
    for (const ext of extsTemporarilyInstalled) {
      delete require.extensions[ext];
    }
  }
}

if (artifact.location) {
  // the file should be the test file
  // tests from other files are not supported
  const map = this.sourceMapCache.get(artifact.location.file)

  if (!map) {
    return rpc().onTaskArtifactRecord(test.id, artifact)
  }

  const traceMap = new DecodedMap(map as any, artifact.location.file)
  const position = getOriginalPosition(traceMap, artifact.location)

  if (position) {
    const { source, column, line } = position
    const file = source || artifact.location.file
    artifact.location = {
      line,
      column: column + 1,
      // if the file path is on windows, we need to remove the starting slash
      file: file.match(/\/\w:\//) ? file.slice(1) : file,
    }

    if (artifact.type === 'internal:annotation') {
      artifact.annotation.location = artifact.location
    }
  }
}

for (; i < children.length; i++) {
  const child = children[i]
  const isCached = isParentCached || getCachedNode(child)
  if (isCached) {
    // presence of cached means child must be a stringifiable node
    const result = analyzeNode(child as StringifiableNode)
    if (result) {
      // node is stringifiable, record state
      nc += result[0]
      ec += result[1]
      currentChunk.push(child as StringifiableNode)
      continue
    }
  }
  // we only reach here if we ran into a node that is not stringifiable
  // check if currently analyzed nodes meet criteria for stringification.
  // adjust iteration index
  i -= stringifyCurrentChunk(i)
  // reset state
  nc = 0
  ec = 0
  currentChunk.length = 0
}

if (opts.compatibilityMode !== false) {
  // ESLint currently doesn't have any portable way for shared configs to
  // specify their own plugins that should be used (cf issue #10125). This
  // will likely get fixed at some point but it'll take time, so in the
  // meantime we'll just add additional fallback entries for common shared
  // configs.

  // Similarly, Gatsby generates files within the `public` folder located
  // within the project, but doesn't pre-resolve the `require` calls to use
  // its own dependencies. Meaning that when PnP see a file from the `public`
  // folder making a require, it thinks that your project forgot to list one
  // of your dependencies.

  for (const name of [`react-scripts`, `gatsby`]) {
    const packageStore = runtimeState.packageRegistry.get(name);
    if (packageStore) {
      for (const reference of packageStore.keys()) {
        if (reference === null) {
          throw new Error(`Assertion failed: This reference shouldn't be null`);
        } else {
          fallbackLocators.push({name, reference});
        }
      }
    }
  }
}

for (const pkg of apiManifest) {
  for (const entry of pkg.entries) {
    if (duplicateEntries.has(entry.name)) {
      continue;
    } else if (entryToModuleMap[entry.name]) {
      delete entryToModuleMap[entry.name];
      duplicateEntries.add(entry.name);
    } else {
      const normalizedModuleName = pkg.moduleName.replace(/^@angular\//, '');

      entryToModuleMap[entry.name] = {moduleName: normalizedModuleName};

      // If there are aliases, create entries for each alias
      if (entry.aliases) {
        for (const alias of entry.aliases) {
          entryToModuleMap[alias] = {
            moduleName: normalizedModuleName,
            targetSymbol: entry.name,
          };
        }
      }
    }
  }
}

if (config.answerSrc) {
  assert(config.answerRootDir, `No \`answerRootDir\` specified for: ${path}`);

  const answersDir = join(path, config.answerSrc);
  const answerRootDir = join(path, config.answerRootDir);

  const answerFilePaths = await glob('**/*', {
    cwd: answersDir,
    onlyFiles: true,
    absolute: false,
  });

  for (const answerFile of answerFilePaths) {
    const absAnswerFile = join(answersDir, answerFile);
    // Relativize answer file path.
    const filePath = relative(answerRootDir, absAnswerFile);
    // We use the absolute file in order to read the content, but the key
    // needs to be a relative path within the project.
    answerFiles[filePath] = getFileContents(absAnswerFile);
  }
} else {
  for (const file of Object.keys(files)) {
    if (answerPrefix.test(file)) {
      answerFiles[file.replace(answerPrefix, '')] = files[file];
    }
  }
}

switch (oldState.kind) {
  case IncrementalStateKind.Fresh:
    // Since this line of program has never been successfully analyzed to begin with, treat
    // this as a fresh compilation.
    return IncrementalCompilation.fresh(newVersions);
  case IncrementalStateKind.Analyzed:
    // The most recent program was analyzed successfully, so we can use that as our prior
    // state and don't need to consider any other deltas except changes in the most recent
    // program.
    priorAnalysis = oldState;
    break;
  case IncrementalStateKind.Delta:
    // There is an ancestor program which was analyzed successfully and can be used as a
    // starting point, but we need to determine what's changed since that program.
    priorAnalysis = oldState.lastAnalyzedState;
    for (const sfPath of oldState.physicallyChangedTsFiles) {
      physicallyChangedTsFiles.add(sfPath);
    }
    for (const resourcePath of oldState.changedResourceFiles) {
      changedResourceFiles.add(resourcePath);
    }
    break;
}

for (const member of classDecl.members) {
  switch (member.kind) {
    case ts.SyntaxKind.PropertyDeclaration:
    case ts.SyntaxKind.GetAccessor:
    case ts.SyntaxKind.SetAccessor:
    case ts.SyntaxKind.MethodDeclaration: {
      const [name, newMember, decorators] = transformClassElement(member);
      newMembers.push(newMember);
      if (name) decoratedProperties.set(name, decorators);
      continue;
    }
    case ts.SyntaxKind.Constructor: {
      const ctor = member as ts.ConstructorDeclaration;
      if (!ctor.body) break;
      const [newMember, parametersInfo] = transformConstructor(
        member as ts.ConstructorDeclaration,
      );
      classParameters = parametersInfo;
      newMembers.push(newMember);
      continue;
    }
    default:
      break;
  }
  newMembers.push(ts.visitEachChild(member, decoratorDownlevelVisitor, context));
}

if (decoratorInput !== null) {
  assert(isInputContainerNode(node), 'Expected input to be declared on accessor or property.');
  const inputDescr = getInputDescriptor(host, node);

  // track all inputs, even from declarations for reference resolution.
  knownDecoratorInputs.register({descriptor: inputDescr, metadata: decoratorInput, node});

  // track source file inputs in the result of this target.
  // these are then later migrated in the migration phase.
  if (decoratorInput.inSourceFile && host.isSourceFileForCurrentMigration(sf)) {
    const conversionPreparation = prepareAndCheckForConversion(
      node,
      decoratorInput,
      checker,
      host.compilerOptions,
    );

    if (isFieldIncompatibility(conversionPreparation)) {
      knownDecoratorInputs.markFieldIncompatible(inputDescr, conversionPreparation);
      result.sourceInputs.set(inputDescr, null);
    } else {
      result.sourceInputs.set(inputDescr, conversionPreparation);
    }
  }
}

for (const ref of refs) {
  if (results.has(ref)) {
    continue;
  }

  results.add(ref);

  const closestTopLevel = closestNode(ref, isTopLevelStatement);
  // Avoid re-traversing the same top-level nodes since we know what the result will be.
  if (!closestTopLevel || traversedTopLevelNodes.has(closestTopLevel)) {
    continue;
  }

  // Keep searching, starting from the closest top-level node. We skip import declarations,
  // because we already know about them and they may put the search into an infinite loop.
  if (
    !ts.isImportDeclaration(closestTopLevel) &&
    isOutsideRange(
      excludeStart,
      excludeEnd,
      closestTopLevel.getStart(),
      closestTopLevel.getEnd(),
    )
  ) {
    traversedTopLevelNodes.add(closestTopLevel);
    walk(closestTopLevel);
  }
}

if (propertyName === 'template' && ts.isStringLiteralLike(property.initializer)) {
  // Need to add an offset of one to the start because the template quotes are
  // not part of the template content.
  // The `getText()` method gives us the original raw text.
  // We could have used the `text` property, but if the template is defined as a backtick
  // string then the `text` property contains a "cooked" version of the string. Such cooked
  // strings will have converted CRLF characters to only LF. This messes up string
  // replacements in template migrations.
  // The raw text returned by `getText()` includes the enclosing quotes so we change the
  // `content` and `start` values accordingly.
  const content = property.initializer.getText().slice(1, -1);
  const start = property.initializer.getStart() + 1;
  this.resolvedTemplates.push({
    filePath: sourceFileName,
    container: node,
    content,
    inline: true,
    start: start,
    getCharacterAndLineOfPosition: (pos) =>
      ts.getLineAndCharacterOfPosition(sourceFile, pos + start),
  });
}

try {
  const tag = path.get('tag');
  if (isLocalize(tag, localizeName)) {
    const [messageParts] = unwrapMessagePartsFromTemplateLiteral(
      path.get('quasi').get('quasis'),
      fs,
    );
    const translated = translate(
      diagnostics,
      translations,
      messageParts,
      path.node.quasi.expressions,
      missingTranslation,
    );
    path.replaceWith(buildLocalizeReplacement(translated[0], translated[1]));
  }
} catch (e) {
  if (isBabelParseError(e)) {
    // If we get a BabelParseError here then something went wrong with Babel itself
    // since there must be something wrong with the structure of the AST generated
    // by Babel parsing a TaggedTemplateExpression.
    throw buildCodeFrameError(fs, path, state.file, e);
  } else {
    throw e;
  }
}

try {
    // get datasources of all actions used in the the application
    let datasourcesUsedInApplication: Datasource[] = yield select(
      getDatasourcesUsedInApplicationByActions,
    );

    // get datasources present in entity explorer and not part of any action.
    if (datasourcesUsedInApplication.length < MAX_DATASOURCE_SUGGESTIONS) {
      const datasourceInEntityExplorer: Datasource[] = yield select(
        getEntityExplorerDatasources,
      );

      datasourcesUsedInApplication = [
        ...datasourcesUsedInApplication,
        ...datasourceInEntityExplorer,
      ];
    }

    //fetch datasource structure for each datasource
    for (const datasource of datasourcesUsedInApplication) {
      yield put(fetchDatasourceStructure(datasource.id, true));
    }
  } catch (error) {}

try {
	const featuresService = accessor.get(ICompletionsFeaturesService);
	const logTarget = accessor.get(ICompletionsLogTargetService);
	let params = cppContextProviderParamsDefault;
	const cppContextProviderParams = featuresService.cppContextProviderParams(telemetryData);
	if (cppContextProviderParams) {
		try {
			params = JSON.parse(cppContextProviderParams) as CppContextProviderParams;
		} catch (e) {
			logger.error(logTarget, 'Failed to parse cppContextProviderParams', e);
		}
	} else {
		const langSpecific = featuresService.getContextProviderExpSettings('cpp')?.params;
		if (langSpecific) {
			params = { ...langSpecific };
		}
	}
	for (const [key, value] of Object.entries(params)) { activeExperiments.set(key, value); }
} catch (e) {
	logger.exception(accessor, e, 'fillInCppActiveExperiments');
}

if (this.#isCommand(commandName, this.#commands.build)) {
  return await this.makeCommand(this.#commands.build);
} else if (this.#isCommand(commandName, this.#commands.serve)) {
  return await this.makeCommand(this.#commands.serve);
} else if (this.#isCommand(commandName, this.#commands.watch)) {
  return await this.makeCommand(this.#commands.watch);
} else if (this.#isCommand(commandName, this.#commands.help)) {
  // Stub for the `help` command
  return await this.makeCommand(this.#commands.help);
} else if (this.#isCommand(commandName, this.#commands.version)) {
  return await this.makeCommand(this.#commands.version);
} else if (this.#isCommand(commandName, this.#commands.info)) {
  return await this.makeCommand(this.#commands.info);
} else if (this.#isCommand(commandName, this.#commands.configtest)) {
  return await this.makeCommand(this.#commands.configtest);
}

if (enable) {
  this.agHelper.CheckUncheck(this._usePreparedStatement, true);
} else {
  // When disabling, click the switch which will trigger the modal
  this.agHelper
    .GetElement(this._usePreparedStatement)
    .click({ force: true });

  // Wait for and handle the confirmation modal
  this.agHelper.AssertElementVisibility(
    commonlocators.confirmationModal,
    true,
    0,
    5000,
  );
  this.agHelper.GetNClick(commonlocators.confirmationModalConfirm);
  this.agHelper.AssertElementAbsence(
    commonlocators.confirmationModal,
    5000,
  );

  // Now verify the switch is actually unchecked
  this.agHelper
    .GetElement(this._usePreparedStatement)
    .should("not.be.checked");
}

if (compiler !== null) {
  // Analyze sync and retrieve necessary dependencies.
  // Note: `getTemplateTypeChecker` requires the `enableTemplateTypeChecker` flag, but
  // this has negative effects as it causes optional TCB operations to execute, which may
  // error with unsuccessful reference emits that previously were ignored outside of the migration.
  // The migration is resilient to TCB information missing, so this is fine, and all the information
  // we need is part of required TCB operations anyway.
  const state = compiler['ensureAnalyzed']();

  resourceLoader = compiler['resourceManager'];
  refEmitter = state.refEmitter;
  metaReader = state.metaReader;
  templateTypeChecker = state.templateTypeChecker;

  // Generate all type check blocks.
  state.templateTypeChecker.generateAllTypeCheckBlocks();
}

try {
  const { fileName } = await migrations.generate()
  if (fileName) {
    logger.info(`Generated successfully (${fileName}).`)

    // Add a 1-second delay after creating a migration file to ensure unique
    // timestamps across modules. MikroORM uses second-precision timestamps
    // (YYYYMMDDHHmmss format), so without this delay, multiple modules
    // processed within the same second would get identical migration filenames.
    // The delay is only added when a migration is actually created, not when
    // skipped due to no schema changes.
    // See: https://github.com/medusajs/medusa/issues/14410
    await setTimeout(1000)
  } else {
    logger.info(`Skipped. No changes detected in your models.`)
  }
} catch (error) {
  logger.error(`Failed with error ${error.message}`, error)
}

if (!options.validExecutorNames.has(executorName)) {
  logger.error(stripIndents`NX The provided build target, ${
    options.buildTarget
  }, uses the '${executorName}' executor.
But only the follow executors are allowed
${Array.from(options.validExecutorNames)
.map((ve) => ` - ${ve}`)
.join('\n')}

${frameworkHelperMessage(Array.from(options.buildTarget), executorName)}
This is most likely because the provided --build-target is not a build target for an application or framework.
For example, the provide build target, '${options.buildTarget}' is:
- the build target for a buildable/publishable library instead of an app.
- using a different framework than expected like react library using an angular or next app build target.

If you do not have an app in the workspace to you can make a new app with 'nx g app' and use it just for component testing
`);

  throw new Error(
    'The provided --build-target does not use an executor in the allow list of executors defined.'
  );
}

try {
  const baseApplicationId: string = yield select(getCurrentBaseApplicationId);
  const response: ApiResponse = yield call(
    GitSyncAPI.getSSHKeyPair,
    baseApplicationId,
  );
  const isValidResponse: boolean = yield validateResponse(response, false);

  if (isValidResponse) {
    // @ts-expect-error: response.data type mismatch
    yield put(getSSHKeyPairSuccess(response.data));

    if (action.onSuccessCallback) {
      // @ts-expect-error: response type mismatch
      action.onSuccessCallback(response);
    }
  }
} catch (error) {
  // @ts-expect-error: getSSHKeyPairError expects string
  yield put(getSSHKeyPairError({ error, show: false }));

  if (action.onErrorCallback) {
    // @ts-expect-error: onErrorCallback expects string
    action.onErrorCallback(error);
  }
}
